def compute_probs(datalist: list) -> (list, list):
    """
    Computes the probabilities for fragments with at least 100 pairs supporting it and that are not more than 10 median deviations from the median.
    Handles None, negative, and string values.
    """
    FILTER_MINREADS = 100
    FILTER_MEDDEV_M = 10
    # Clean data: convert strings to int, filter out None and negative
    cleaned = []
    for item in datalist:
        if item is None:
            continue
        if isinstance(item, str):
            try:
                item = int(item)
            except ValueError:
                continue
        if isinstance(item, (int, float)) and item > 0:
            cleaned.append(item)
    if not cleaned:
        return [], []
    med = median(cleaned)
    mad = median_absolute_deviation(cleaned)
    values = []
    probabilities = []
    for item in sorted(set(cleaned)):
        if item <= med + FILTER_MEDDEV_M * mad:
            data_count = cleaned.count(item)
            if data_count >= FILTER_MINREADS:
                values.append(item)
                probabilities.append(data_count)
    count_sum = float(sum(probabilities))
    if count_sum == 0:
        return [], []
    probabilities = [n / count_sum for n in probabilities]
    return values, probabilities

